custom_css:
/* ========================================
   TEMA GOOGLE MATERIAL DESIGN
   Estilo inspirado nos produtos Google
   ======================================== */

/* Estilo geral - bordas arredondadas e minimalistas */
QMainWindow {
    background-color: #ffffff;
}

/* Área de texto - estilo Google Docs */
QPlainTextEdit {
    background-color: #ffffff;
    color: #202124;
    font-family: 'Roboto', 'Segoe UI', 'Arial', sans-serif;
    font-size: 11pt;
    line-height: 1.5;
    border: none;
    padding: 20px;
    selection-background-color: #e8f0fe;
    selection-color: #1a73e8;
}

/* Barra de menus - estilo Google */
QMenuBar {
    background-color: #ffffff;
    color: #5f6368;
    font-family: 'Roboto', 'Segoe UI', 'Arial', sans-serif;
    font-size: 10pt;
    border-bottom: 1px solid #e8eaed;
    padding: 4px 0px;
}

QMenuBar::item {
    background-color: transparent;
    padding: 8px 12px;
    margin: 0px 2px;
    border-radius: 4px;
}

QMenuBar::item:selected {
    background-color: #f1f3f4;
    color: #202124;
}

QMenuBar::item:pressed {
    background-color: #e8eaed;
}

/* Menus dropdown - estilo Google */
QMenu {
    background-color: #ffffff;
    color: #202124;
    border: 1px solid #e8eaed;
    border-radius: 8px;
    padding: 8px 0px;
    font-family: 'Roboto', 'Segoe UI', 'Arial', sans-serif;
    font-size: 10pt;
}

QMenu::item {
    padding: 8px 32px 8px 16px;
    margin: 0px 8px;
    border-radius: 4px;
}

QMenu::item:selected {
    background-color: #f1f3f4;
    color: #1a73e8;
}

QMenu::separator {
    height: 1px;
    background-color: #e8eaed;
    margin: 8px 0px;
}

/* Barra de ferramentas - estilo Google */
QToolBar {
    background-color: #ffffff;
    border: none;
    border-bottom: 1px solid #e8eaed;
    padding: 4px 8px;
    spacing: 4px;
}

QToolBar QToolButton {
    background-color: transparent;
    border: none;
    border-radius: 4px;
    padding: 6px 8px;
    margin: 0px 2px;
    color: #5f6368;
    font-family: 'Roboto', 'Segoe UI', 'Arial', sans-serif;
    font-size: 10pt;
}

QToolBar QToolButton:hover {
    background-color: #f1f3f4;
    color: #202124;
}

QToolBar QToolButton:pressed {
    background-color: #e8eaed;
}

/* Botões - estilo Google */
QPushButton {
    background-color: #1a73e8;
    color: #ffffff;
    border: none;
    border-radius: 4px;
    padding: 8px 16px;
    font-family: 'Roboto', 'Segoe UI', 'Arial', sans-serif;
    font-size: 10pt;
    font-weight: 500;
    letter-spacing: 0.25px;
}

QPushButton:hover {
    background-color: #1557b0;
}

QPushButton:pressed {
    background-color: #0f3d7a;
}

QPushButton:disabled {
    background-color: #e8eaed;
    color: #80868b;
}

/* Campos de texto - estilo Google */
QLineEdit {
    background-color: #ffffff;
    color: #202124;
    border: 1px solid #dadce0;
    border-radius: 4px;
    padding: 8px 12px;
    font-family: 'Roboto', 'Segoe UI', 'Arial', sans-serif;
    font-size: 10pt;
}

QLineEdit:focus {
    border-color: #1a73e8;
    outline: none;
}

QLineEdit:hover {
    border-color: #bdc1c6;
}

/* Barra de status - estilo Google */
QStatusBar {
    background-color: #f8f9fa;
    color: #5f6368;
    font-family: 'Roboto', 'Segoe UI', 'Arial', sans-serif;
    font-size: 9pt;
    border-top: 1px solid #e8eaed;
}

/* Dock Widget - estilo Google */
QDockWidget::title {
    background-color: #f8f9fa;
    padding: 8px 12px;
    font-family: 'Roboto', 'Segoe UI', 'Arial', sans-serif;
    font-size: 10pt;
    font-weight: 500;
    color: #202124;
    border-bottom: 1px solid #e8eaed;
}

/* Abas (Tabs) - estilo Google Chrome */
QTabWidget::pane {
    background-color: #ffffff;
    border: 1px solid #e8eaed;
    border-radius: 0px;
    top: -1px;
}

QTabBar::tab {
    background-color: #f8f9fa;
    color: #5f6368;
    padding: 10px 20px;
    margin-right: 2px;
    font-family: 'Roboto', 'Segoe UI', 'Arial', sans-serif;
    font-size: 10pt;
    border: 1px solid #e8eaed;
    border-bottom: none;
    border-top-left-radius: 8px;
    border-top-right-radius: 8px;
}

QTabBar::tab:selected {
    background-color: #ffffff;
    color: #1a73e8;
    border-bottom: 2px solid #1a73e8;
}

QTabBar::tab:hover:!selected {
    background-color: #f1f3f4;
    color: #202124;
}

/* Barra de rolagem - estilo Google */
QScrollBar:vertical {
    background-color: #ffffff;
    width: 12px;
    border: none;
    border-radius: 0px;
}

QScrollBar::handle:vertical {
    background-color: #dadce0;
    border-radius: 6px;
    min-height: 20px;
}

QScrollBar::handle:vertical:hover {
    background-color: #bdc1c6;
}

QScrollBar::add-line:vertical, QScrollBar::sub-line:vertical {
    border: none;
    background: none;
}

QScrollBar:horizontal {
    background-color: #ffffff;
    height: 12px;
    border: none;
    border-radius: 0px;
}

QScrollBar::handle:horizontal {
    background-color: #dadce0;
    border-radius: 6px;
    min-width: 20px;
}

QScrollBar::handle:horizontal:hover {
    background-color: #bdc1c6;
}

/* Tooltips - estilo Google */
QToolTip {
    background-color: #202124;
    color: #ffffff;
    border: none;
    border-radius: 4px;
    padding: 6px 10px;
    font-family: 'Roboto', 'Segoe UI', 'Arial', sans-serif;
    font-size: 9pt;
}

/* Barra de busca - estilo Google */
#search-bar {
    background-color: #f8f9fa;
    border-top: 1px solid #e8eaed;
    border-bottom: 1px solid #e8eaed;
    padding: 8px;
}

/* Checkbox - estilo Google */
QCheckBox {
    spacing: 8px;
    font-family: 'Roboto', 'Segoe UI', 'Arial', sans-serif;
    font-size: 10pt;
    color: #202124;
}

QCheckBox::indicator {
    width: 18px;
    height: 18px;
    border-radius: 2px;
    border: 2px solid #5f6368;
}

QCheckBox::indicator:checked {
    background-color: #1a73e8;
    border-color: #1a73e8;
}

/* Radio Button - estilo Google */
QRadioButton {
    spacing: 8px;
    font-family: 'Roboto', 'Segoe UI', 'Arial', sans-serif;
    font-size: 10pt;
    color: #202124;
}

QRadioButton::indicator {
    width: 18px;
    height: 18px;
    border-radius: 9px;
    border: 2px solid #5f6368;
}

QRadioButton::indicator:checked {
    background-color: #1a73e8;
    border-color: #1a73e8;
}

/* Combobox - estilo Google */
QComboBox {
    background-color: #ffffff;
    border: 1px solid #dadce0;
    border-radius: 4px;
    padding: 6px 30px 6px 12px;
    font-family: 'Roboto', 'Segoe UI', 'Arial', sans-serif;
    font-size: 10pt;
    color: #202124;
}

QComboBox:hover {
    border-color: #bdc1c6;
}

QComboBox::drop-down {
    border: none;
}

QComboBox::down-arrow {
    image: none;
    border-left: 5px solid transparent;
    border-right: 5px solid transparent;
    border-top: 5px solid #5f6368;
    margin-right: 8px;
}

/* Group Box - estilo Google */
QGroupBox {
    font-family: 'Roboto', 'Segoe UI', 'Arial', sans-serif;
    font-size: 10pt;
    font-weight: bold;
    color: #202124;
    border: 1px solid #e8eaed;
    border-radius: 8px;
    margin-top: 12px;
    padding-top: 12px;
}

QGroupBox::title {
    subcontrol-origin: margin;
    left: 12px;
    padding: 0 8px;
    color: #1a73e8;
}
